1	package com.eaglepoint.workforce.service;
2	
3	import com.eaglepoint.workforce.entity.PaymentTransaction;
4	import com.eaglepoint.workforce.entity.Refund;
5	import com.eaglepoint.workforce.enums.PaymentChannel;
6	import com.eaglepoint.workforce.enums.PaymentStatus;
7	import com.eaglepoint.workforce.repository.PaymentTransactionRepository;
8	import com.eaglepoint.workforce.repository.RefundRepository;
9	import org.springframework.stereotype.Service;
10	import org.springframework.transaction.annotation.Transactional;
11	
12	import java.math.BigDecimal;
13	import java.security.MessageDigest;
14	import java.time.LocalDateTime;
15	import java.util.List;
16	import java.util.Optional;
17	
18	@Service
19	public class PaymentService {
20	
21	    private final PaymentTransactionRepository paymentRepo;
22	    private final RefundRepository refundRepo;
23	
24	    public PaymentService(PaymentTransactionRepository paymentRepo, RefundRepository refundRepo) {
25	        this.paymentRepo = paymentRepo;
26	        this.refundRepo = refundRepo;
27	    }
28	
29	    @Transactional
30	    public PaymentTransaction recordPayment(String idempotencyKey, String referenceNumber,
31	                                             BigDecimal amount, PaymentChannel channel,
32	                                             String location, String payerName, String description,
33	                                             String checkNumber, String cardLastFour,
34	                                             Long recordedBy, String recordedByUsername) {
35	        Optional<PaymentTransaction> existing = paymentRepo.findByIdempotencyKey(idempotencyKey);
36	        if (existing.isPresent()) {
37	            return existing.get();
38	        }
39	
40	        if (amount == null || amount.compareTo(BigDecimal.ZERO) <= 0) {
41	            throw new IllegalArgumentException("Payment amount must be positive");
42	        }
43	
44	        PaymentTransaction payment = new PaymentTransaction();
45	        payment.setIdempotencyKey(idempotencyKey);
46	        payment.setReferenceNumber(referenceNumber);
47	        payment.setAmount(amount);
48	        payment.setChannel(channel);
49	        payment.setLocation(location);
50	        payment.setPayerName(payerName);
51	        payment.setDescription(description);
52	        payment.setCheckNumber(checkNumber);
53	        payment.setCardLastFour(cardLastFour);
54	        payment.setRecordedBy(recordedBy);
55	        payment.setRecordedByUsername(recordedByUsername);
56	        payment.setTransactionDate(LocalDateTime.now());
57	        payment.setStatus(PaymentStatus.RECORDED);
58	
59	        return paymentRepo.save(payment);
60	    }
61	
62	    @Transactional
63	    public Refund processRefund(Long paymentId, BigDecimal refundAmount, String reason,
64	                                 Long processedBy, String processedByUsername) {
65	        PaymentTransaction payment = paymentRepo.findById(paymentId)
66	                .orElseThrow(() -> new RuntimeException("Payment not found: " + paymentId));
67	
68	        if (refundAmount == null || refundAmount.compareTo(BigDecimal.ZERO) <= 0) {
69	            throw new IllegalArgumentException("Refund amount must be positive");
70	        }
71	
72	        BigDecimal maxRefundable = payment.getAmount().subtract(payment.getRefundedAmount());
73	        if (refundAmount.compareTo(maxRefundable) > 0) {
74	            throw new RuntimeException("Refund amount " + refundAmount +
75	                    " exceeds available amount " + maxRefundable);
76	        }
77	
78	        Refund refund = new Refund();
79	        refund.setPayment(payment);
80	        refund.setAmount(refundAmount);
81	        refund.setReason(reason);
82	        refund.setProcessedBy(processedBy);
83	        refund.setProcessedByUsername(processedByUsername);
84	        refund = refundRepo.save(refund);
85	
86	        payment.setRefundedAmount(payment.getRefundedAmount().add(refundAmount));
87	        if (payment.getRefundedAmount().compareTo(payment.getAmount()) >= 0) {
88	            payment.setStatus(PaymentStatus.REFUNDED);
89	        } else {
90	            payment.setStatus(PaymentStatus.PARTIALLY_REFUNDED);
91	        }
92	        paymentRepo.save(payment);
93	
94	        return refund;
95	    }
96	
97	    @Transactional(readOnly = true)
98	    public List<PaymentTransaction> findAll() {
99	        return paymentRepo.findAllByOrderByTransactionDateDesc();
100	    }
101	
102	    @Transactional(readOnly = true)
103	    public Optional<PaymentTransaction> findById(Long id) {
104	        return paymentRepo.findById(id);
105	    }
106	
107	    @Transactional(readOnly = true)
108	    public List<Refund> getRefundsForPayment(Long paymentId) {
109	        return refundRepo.findByPaymentIdOrderByCreatedAtDesc(paymentId);
110	    }
111	
112	    @Transactional(readOnly = true)
113	    public List<PaymentTransaction> findByLocationAndDateRange(String location,
114	                                                                LocalDateTime from, LocalDateTime to) {
115	        return paymentRepo.findByLocationAndTransactionDateBetween(location, from, to);
116	    }
117	
118	    @Transactional(readOnly = true)
119	    public List<String> getDistinctLocations() {
120	        return paymentRepo.findDistinctLocations();
121	    }
122	
123	    /**
124	     * Deterministic idempotency key from business fields only (no timestamp).
125	     * Same reference + channel + amount always produces the same key.
126	     */
127	    public static String generateIdempotencyKey(String referenceNumber, String channel, String amount) {
128	        try {
129	            String input = referenceNumber + "|" + channel + "|" + amount;
130	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
131	            byte[] hash = digest.digest(input.getBytes());
132	            StringBuilder hex = new StringBuilder();
133	            for (byte b : hash) hex.append(String.format("%02x", b));
134	            return hex.toString();
135	        } catch (Exception e) {
136	            throw new RuntimeException("Failed to generate idempotency key", e);
137	        }
138	    }
139	}
