1	package com.eaglepoint.workforce.service;
2	
3	import com.eaglepoint.workforce.entity.*;
4	import com.eaglepoint.workforce.enums.ImportStatus;
5	import com.eaglepoint.workforce.repository.*;
6	import org.apache.poi.ss.usermodel.*;
7	import org.apache.poi.xssf.usermodel.XSSFWorkbook;
8	import org.springframework.beans.factory.annotation.Value;
9	import org.springframework.scheduling.annotation.Async;
10	import org.springframework.stereotype.Service;
11	import org.springframework.transaction.annotation.Transactional;
12	import org.springframework.web.multipart.MultipartFile;
13	
14	import java.io.*;
15	import java.nio.file.Files;
16	import java.nio.file.Path;
17	import java.nio.file.Paths;
18	import java.security.MessageDigest;
19	import java.time.LocalDateTime;
20	import java.util.*;
21	
22	@Service
23	public class ImportService {
24	
25	    @Value("${app.import.storage-path:./imports}")
26	    private String storagePath;
27	
28	    private final ImportJobRepository importJobRepo;
29	    private final DepartmentRepository departmentRepo;
30	    private final TrainingCourseRepository courseRepo;
31	
32	    public ImportService(ImportJobRepository importJobRepo,
33	                          DepartmentRepository departmentRepo,
34	                          TrainingCourseRepository courseRepo) {
35	        this.importJobRepo = importJobRepo;
36	        this.departmentRepo = departmentRepo;
37	        this.courseRepo = courseRepo;
38	    }
39	
40	    @Transactional
41	    public ImportJob prepareImport(MultipartFile file, String importType, Long createdBy) throws Exception {
42	        String fingerprint = computeSha256(file.getInputStream());
43	
44	        if (importJobRepo.existsByFileFingerprint(fingerprint)) {
45	            ImportJob dup = new ImportJob();
46	            dup.setOriginalFileName(file.getOriginalFilename());
47	            dup.setImportType(importType);
48	            dup.setFileFingerprint(fingerprint);
49	            dup.setStatus(ImportStatus.DUPLICATE);
50	            dup.setCreatedBy(createdBy);
51	            dup.setErrorReport("This file has already been imported (SHA-256: " + fingerprint + ")");
52	            return importJobRepo.save(dup);
53	        }
54	
55	        Path dir = Paths.get(storagePath);
56	        Files.createDirectories(dir);
57	        String savedName = System.currentTimeMillis() + "_" + file.getOriginalFilename();
58	        Path savedPath = dir.resolve(savedName);
59	        file.transferTo(savedPath.toFile());
60	
61	        ImportJob job = new ImportJob();
62	        job.setOriginalFileName(file.getOriginalFilename());
63	        job.setImportType(importType);
64	        job.setFileFingerprint(fingerprint);
65	        job.setFilePath(savedPath.toString());
66	        job.setStatus(ImportStatus.QUEUED);
67	        job.setCreatedBy(createdBy);
68	        return importJobRepo.save(job);
69	    }
70	
71	    @Async("importExecutor")
72	    public void executeImport(Long jobId) {
73	        ImportJob job = importJobRepo.findById(jobId).orElse(null);
74	        if (job == null || job.getStatus() == ImportStatus.DUPLICATE) return;
75	
76	        job.setStatus(ImportStatus.VALIDATING);
77	        importJobRepo.save(job);
78	
79	        try {
80	            Path filePath = Paths.get(job.getFilePath());
81	            String fileName = job.getOriginalFileName().toLowerCase();
82	            List<String[]> rows;
83	
84	            if (fileName.endsWith(".xlsx") || fileName.endsWith(".xls")) {
85	                rows = readExcel(filePath);
86	            } else if (fileName.endsWith(".csv")) {
87	                rows = readCsv(filePath);
88	            } else {
89	                throw new RuntimeException("Unsupported file format. Use .xlsx, .xls, or .csv");
90	            }
91	
92	            if (rows.isEmpty()) {
93	                throw new RuntimeException("File is empty");
94	            }
95	
96	            job.setStatus(ImportStatus.IMPORTING);
97	            job.setTotalRows(rows.size() - 1); // exclude header
98	            importJobRepo.save(job);
99	
100	            String[] header = rows.get(0);
101	            validateHeaderSchema(job.getImportType(), header);
102	
103	            List<String> errors = new ArrayList<>();
104	            int successCount = 0;
105	
106	            for (int i = 1; i < rows.size(); i++) {
107	                String[] row = rows.get(i);
108	                try {
109	                    validateAndImportRow(job.getImportType(), header, row, i);
110	                    successCount++;
111	                } catch (Exception e) {
112	                    errors.add("Row " + (i + 1) + ": " + e.getMessage());
113	                }
114	            }
115	
116	            job.setSuccessRows(successCount);
117	            job.setErrorRows(errors.size());
118	            job.setErrorReport(errors.isEmpty() ? null : String.join("\n", errors));
119	            job.setStatus(errors.isEmpty() ? ImportStatus.COMPLETED : ImportStatus.COMPLETED_WITH_ERRORS);
120	            job.setCompletedAt(LocalDateTime.now());
121	        } catch (Exception e) {
122	            job.setStatus(ImportStatus.FAILED);
123	            job.setErrorReport(e.getMessage());
124	            job.setCompletedAt(LocalDateTime.now());
125	        }
126	        importJobRepo.save(job);
127	    }
128	
129	    @Transactional(readOnly = true)
130	    public List<ImportJob> findAll() {
131	        return importJobRepo.findAllByOrderByCreatedAtDesc();
132	    }
133	
134	    @Transactional(readOnly = true)
135	    public Optional<ImportJob> findById(Long id) {
136	        return importJobRepo.findById(id);
137	    }
138	
139	    private static final Map<String, Set<String>> REQUIRED_HEADERS = Map.of(
140	            "departments", Set.of("Code", "Name"),
141	            "courses", Set.of("Code", "Name")
142	    );
143	
144	    void validateHeaderSchema(String importType, String[] header) {
145	        Set<String> required = REQUIRED_HEADERS.get(importType);
146	        if (required == null) {
147	            throw new RuntimeException("Unknown import type: " + importType);
148	        }
149	        Set<String> actual = new HashSet<>();
150	        for (String h : header) actual.add(h.trim());
151	
152	        List<String> missing = new ArrayList<>();
153	        for (String r : required) {
154	            if (!actual.contains(r)) missing.add(r);
155	        }
156	        if (!missing.isEmpty()) {
157	            throw new RuntimeException("Missing required column(s): " + String.join(", ", missing)
158	                    + ". Expected schema: " + required);
159	        }
160	    }
161	
162	    @Transactional
163	    void validateAndImportRow(String importType, String[] header, String[] row, int rowIndex) {
164	        switch (importType) {
165	            case "departments" -> importDepartmentRow(header, row, rowIndex);
166	            case "courses" -> importCourseRow(header, row, rowIndex);
167	            default -> throw new RuntimeException("Unknown import type: " + importType);
168	        }
169	    }
170	
171	    private void importDepartmentRow(String[] header, String[] row, int rowIndex) {
172	        Map<String, String> map = zipToMap(header, row);
173	        String code = requireField(map, "Code", rowIndex);
174	        String name = requireField(map, "Name", rowIndex);
175	
176	        if (departmentRepo.existsByCode(code)) {
177	            Department existing = departmentRepo.findByCode(code).orElseThrow();
178	            existing.setName(name);
179	            existing.setHeadName(map.getOrDefault("Head Name", existing.getHeadName()));
180	            departmentRepo.save(existing);
181	        } else {
182	            Department dept = new Department();
183	            dept.setCode(code);
184	            dept.setName(name);
185	            dept.setHeadName(map.get("Head Name"));
186	            dept.setActive(!"No".equalsIgnoreCase(map.get("Active")));
187	            departmentRepo.save(dept);
188	        }
189	    }
190	
191	    private void importCourseRow(String[] header, String[] row, int rowIndex) {
192	        Map<String, String> map = zipToMap(header, row);
193	        String code = requireField(map, "Code", rowIndex);
194	        String name = requireField(map, "Name", rowIndex);
195	
196	        if (courseRepo.existsByCode(code)) {
197	            TrainingCourse existing = courseRepo.findByCode(code).orElseThrow();
198	            existing.setName(name);
199	            existing.setDescription(map.getOrDefault("Description", existing.getDescription()));
200	            if (map.containsKey("Credit Hours")) {
201	                try { existing.setCreditHours(Integer.parseInt(map.get("Credit Hours"))); } catch (NumberFormatException ignored) {}
202	            }
203	            courseRepo.save(existing);
204	        } else {
205	            TrainingCourse course = new TrainingCourse();
206	            course.setCode(code);
207	            course.setName(name);
208	            course.setDescription(map.get("Description"));
209	            if (map.containsKey("Credit Hours")) {
210	                try { course.setCreditHours(Integer.parseInt(map.get("Credit Hours"))); } catch (NumberFormatException ignored) {}
211	            }
212	            course.setMandatory("Yes".equalsIgnoreCase(map.get("Mandatory")));
213	            course.setActive(!"No".equalsIgnoreCase(map.get("Active")));
214	            courseRepo.save(course);
215	        }
216	    }
217	
218	    private String requireField(Map<String, String> map, String field, int rowIndex) {
219	        String val = map.get(field);
220	        if (val == null || val.isBlank()) {
221	            throw new RuntimeException("Missing required field '" + field + "'");
222	        }
223	        return val.trim();
224	    }
225	
226	    private Map<String, String> zipToMap(String[] header, String[] row) {
227	        Map<String, String> map = new LinkedHashMap<>();
228	        for (int i = 0; i < header.length; i++) {
229	            map.put(header[i].trim(), i < row.length ? (row[i] != null ? row[i].trim() : "") : "");
230	        }
231	        return map;
232	    }
233	
234	    private List<String[]> readExcel(Path path) throws IOException {
235	        List<String[]> rows = new ArrayList<>();
236	        try (InputStream is = Files.newInputStream(path); Workbook wb = new XSSFWorkbook(is)) {
237	            Sheet sheet = wb.getSheetAt(0);
238	            for (Row row : sheet) {
239	                String[] cells = new String[row.getLastCellNum()];
240	                for (int i = 0; i < cells.length; i++) {
241	                    Cell cell = row.getCell(i);
242	                    cells[i] = cell != null ? getCellStringValue(cell) : "";
243	                }
244	                rows.add(cells);
245	            }
246	        }
247	        return rows;
248	    }
249	
250	    private String getCellStringValue(Cell cell) {
251	        return switch (cell.getCellType()) {
252	            case STRING -> cell.getStringCellValue();
253	            case NUMERIC -> String.valueOf((long) cell.getNumericCellValue());
254	            case BOOLEAN -> String.valueOf(cell.getBooleanCellValue());
255	            default -> "";
256	        };
257	    }
258	
259	    private List<String[]> readCsv(Path path) throws IOException {
260	        List<String[]> rows = new ArrayList<>();
261	        try (BufferedReader br = Files.newBufferedReader(path)) {
262	            String line;
263	            while ((line = br.readLine()) != null) {
264	                rows.add(parseCsvLine(line));
265	            }
266	        }
267	        return rows;
268	    }
269	
270	    private String[] parseCsvLine(String line) {
271	        List<String> fields = new ArrayList<>();
272	        StringBuilder sb = new StringBuilder();
273	        boolean inQuotes = false;
274	        for (int i = 0; i < line.length(); i++) {
275	            char c = line.charAt(i);
276	            if (c == '"') {
277	                if (inQuotes && i + 1 < line.length() && line.charAt(i + 1) == '"') {
278	                    sb.append('"');
279	                    i++;
280	                } else {
281	                    inQuotes = !inQuotes;
282	                }
283	            } else if (c == ',' && !inQuotes) {
284	                fields.add(sb.toString());
285	                sb.setLength(0);
286	            } else {
287	                sb.append(c);
288	            }
289	        }
290	        fields.add(sb.toString());
291	        return fields.toArray(new String[0]);
292	    }
293	
294	    static String computeSha256(InputStream is) throws Exception {
295	        MessageDigest digest = MessageDigest.getInstance("SHA-256");
296	        byte[] buf = new byte[8192];
297	        int n;
298	        while ((n = is.read(buf)) != -1) {
299	            digest.update(buf, 0, n);
300	        }
301	        byte[] hash = digest.digest();
302	        StringBuilder hex = new StringBuilder();
303	        for (byte b : hash) {
304	            hex.append(String.format("%02x", b));
305	        }
306	        return hex.toString();
307	    }
308	}
