55	    @Transactional(readOnly = true)
56	    public List<UnifiedSearchResult> search(UnifiedSearchRequest request) {
57	        List<UnifiedSearchResult> results = new ArrayList<>();
58	        Set<SearchDomain> domains = request.getDomains();
59	        if (domains == null || domains.isEmpty()) {
60	            domains = EnumSet.allOf(SearchDomain.class);
61	        }
62	        String kw = request.getKeyword();
63	        boolean hasKeyword = kw != null && !kw.isBlank();
64	        String kwLower = hasKeyword ? kw.toLowerCase() : "";
65	
66	        if (domains.contains(SearchDomain.CANDIDATES)) {
67	            List<CandidateProfile> candidates = hasKeyword
68	                    ? candidateRepo.searchByKeyword(kw) : candidateRepo.findAll();
69	            for (CandidateProfile c : candidates) {
70	                if (matchesLocation(c.getLocation(), request.getLocationFilter())) {
71	                    results.add(new UnifiedSearchResult(SearchDomain.CANDIDATES, c.getId(),
72	                            c.getFullName(), c.getCurrentTitle(),
73	                            c.getPipelineStage().getDisplayName(),
74	                            "/recruiter/candidates/" + c.getId()));
75	                }
76	            }
77	        }
78	
79	        if (domains.contains(SearchDomain.COLLECTORS)) {
80	            for (CollectorProfile c : collectorRepo.findAll()) {
81	                if (hasKeyword && !matches(c.getFullName(), kwLower)
82	                        && !matches(c.getEmployeeId(), kwLower)
83	                        && !matches(c.getZone(), kwLower)) continue;
84	                if (!matchesLocation(c.getZone(), request.getLocationFilter())) continue;
85	                results.add(new UnifiedSearchResult(SearchDomain.COLLECTORS, c.getId(),
86	                        c.getFullName(), "Employee: " + (c.getEmployeeId() != null ? c.getEmployeeId() : "-"),
87	                        c.getStatus().getDisplayName(),
88	                        "/dispatch/collectors/" + c.getId()));
89	            }
90	        }
91	
92	        if (domains.contains(SearchDomain.SITES)) {
93	            for (SiteProfile s : siteRepo.findAll()) {
94	                if (hasKeyword && !matches(s.getName(), kwLower)
95	                        && !matches(s.getAddress(), kwLower)
96	                        && !matches(s.getZone(), kwLower)) continue;
97	                if (!matchesLocation(s.getZone(), request.getLocationFilter())) continue;
98	                results.add(new UnifiedSearchResult(SearchDomain.SITES, s.getId(),
99	                        s.getName(), s.getAddress(),
100	                        s.isActive() ? "Active" : "Inactive",
101	                        "/dispatch/sites/" + s.getId()));
102	            }
103	        }
104	
105	        if (domains.contains(SearchDomain.REQUISITIONS)) {
106	            for (Requisition r : requisitionRepo.findAll()) {
107	                if (hasKeyword && !matches(r.getTitle(), kwLower)
108	                        && !matches(r.getDescription(), kwLower)) continue;
109	                if (request.getStatusFilter() != null && !request.getStatusFilter().isBlank()
110	                        && !r.getStatus().name().equalsIgnoreCase(request.getStatusFilter())) continue;
111	                results.add(new UnifiedSearchResult(SearchDomain.REQUISITIONS, r.getId(),
112	                        r.getTitle(), r.getDescription(),
113	                        r.getStatus().name(), "#"));
114	            }
115	        }
116	
117	        if (domains.contains(SearchDomain.DISPATCH_ASSIGNMENTS)) {
118	            for (DispatchAssignment d : dispatchRepo.findAllWithDetails()) {
119	                if (hasKeyword && !matches(d.getTitle(), kwLower)
120	                        && !matches(d.getDescription(), kwLower)) continue;
121	                if (request.getStatusFilter() != null && !request.getStatusFilter().isBlank()
122	                        && !d.getStatus().name().equalsIgnoreCase(request.getStatusFilter())) continue;
123	                results.add(new UnifiedSearchResult(SearchDomain.DISPATCH_ASSIGNMENTS, d.getId(),
124	                        d.getTitle(), "Site: " + d.getSite().getName(),
125	                        d.getStatus().getDisplayName(),
126	                        "/dispatch/assignments/" + d.getId()));
127	            }
128	        }
129	
130	        if (domains.contains(SearchDomain.DEPARTMENTS)) {
131	            for (Department dept : departmentRepo.findAll()) {
132	                if (hasKeyword && !matches(dept.getName(), kwLower)
133	                        && !matches(dept.getCode(), kwLower)) continue;
134	                results.add(new UnifiedSearchResult(SearchDomain.DEPARTMENTS, dept.getId(),
135	                        dept.getCode() + " - " + dept.getName(), dept.getHeadName(),
136	                        dept.isActive() ? "Active" : "Inactive",
137	                        "/masterdata/departments"));
138	            }
139	        }
140	
141	        if (domains.contains(SearchDomain.TRAINING_COURSES)) {
142	            for (TrainingCourse tc : courseRepo.findAll()) {
143	                if (hasKeyword && !matches(tc.getName(), kwLower)
144	                        && !matches(tc.getCode(), kwLower)
145	                        && !matches(tc.getDescription(), kwLower)) continue;
146	                results.add(new UnifiedSearchResult(SearchDomain.TRAINING_COURSES, tc.getId(),
147	                        tc.getCode() + " - " + tc.getName(), tc.getDescription(),
148	                        tc.isActive() ? "Active" : "Inactive",
149	                        "/masterdata/courses"));
150	            }
151	        }
152	
153	        if (domains.contains(SearchDomain.MEMBERS)) {
154	            List<Member> members = hasKeyword ? memberRepo.findByFullNameContainingIgnoreCase(kw) : memberRepo.findAll();
155	            for (Member m : members) {
156	                results.add(new UnifiedSearchResult(SearchDomain.MEMBERS, m.getId(),
157	                        m.getMemberCode() + " - " + m.getFullName(), m.getMembershipTier(),
158	                        m.isActive() ? "Active" : "Inactive", "#"));
159	            }
160	        }
161	
162	        if (domains.contains(SearchDomain.ENTERPRISES)) {
163	            List<Enterprise> ents = hasKeyword ? enterpriseRepo.findByNameContainingIgnoreCase(kw) : enterpriseRepo.findAll();
164	            for (Enterprise e : ents) {
165	                if (!matchesLocation(e.getLocation(), request.getLocationFilter())) continue;
166	                results.add(new UnifiedSearchResult(SearchDomain.ENTERPRISES, e.getId(),
167	                        e.getEnterpriseCode() + " - " + e.getName(), e.getIndustry(),
168	                        e.isActive() ? "Active" : "Inactive", "#"));
169	            }
170	        }
171	
172	        if (domains.contains(SearchDomain.RESOURCES)) {
173	            List<Resource> resources = hasKeyword ? resourceRepo.findByNameContainingIgnoreCase(kw) : resourceRepo.findAll();
174	            for (Resource r : resources) {
175	                if (!matchesLocation(r.getLocation(), request.getLocationFilter())) continue;
176	                results.add(new UnifiedSearchResult(SearchDomain.RESOURCES, r.getId(),
177	                        r.getResourceCode() + " - " + r.getName(), r.getResourceType(),
178	                        r.isAvailable() ? "Available" : "Unavailable", "#"));
179	            }
180	        }
181	
182	        if (domains.contains(SearchDomain.ORDERS)) {
183	            List<ServiceOrder> orders = hasKeyword
184	                    ? orderRepo.findByOrderCodeContainingIgnoreCaseOrDescriptionContainingIgnoreCase(kw, kw)
185	                    : orderRepo.findAll();
186	            for (ServiceOrder o : orders) {
187	                if (request.getStatusFilter() != null && !request.getStatusFilter().isBlank()
188	                        && !o.getStatus().equalsIgnoreCase(request.getStatusFilter())) continue;
189	                results.add(new UnifiedSearchResult(SearchDomain.ORDERS, o.getId(),
190	                        o.getOrderCode(), o.getDescription(), o.getStatus(), "#"));
191	            }
192	        }
193	
194	        if (domains.contains(SearchDomain.REDEMPTIONS)) {
195	            List<RedemptionRecord> recs = hasKeyword
196	                    ? redemptionRepo.findByRedemptionCodeContainingIgnoreCaseOrItemDescriptionContainingIgnoreCase(kw, kw)
197	                    : redemptionRepo.findAll();
198	            for (RedemptionRecord r : recs) {
199	                results.add(new UnifiedSearchResult(SearchDomain.REDEMPTIONS, r.getId(),
200	                        r.getRedemptionCode(), r.getItemDescription(), r.getStatus(), "#"));
201	            }
202	        }
203	
204	        return results;
205	    }
206	
207	    private boolean matches(String field, String kwLower) {
208	        return field != null && field.toLowerCase().contains(kwLower);
209	    }
210	
211	    private boolean matchesLocation(String field, String filter) {
212	        if (filter == null || filter.isBlank()) return true;
213	        return field != null && field.toLowerCase().contains(filter.toLowerCase());
214	    }
215	}
