46	    @Transactional
47	    public ExportJob queueExport(String name, String exportType, String fileFormat,
48	                                  String searchCriteriaJson, Long createdBy) {
49	        ExportJob job = new ExportJob();
50	        job.setName(name);
51	        job.setExportType(exportType);
52	        job.setFileFormat(fileFormat);
53	        job.setSearchCriteriaJson(searchCriteriaJson);
54	        job.setCreatedBy(createdBy);
55	        job.setStatus(ExportStatus.QUEUED);
56	        return exportJobRepo.save(job);
