116	    private int exportToExcel(String type, Path filePath) throws IOException {
117	        try (Workbook wb = new XSSFWorkbook()) {
118	            Sheet sheet = wb.createSheet("Export");
119	            int rowNum = 0;
120	
121	            switch (type) {
122	                case "candidates" -> rowNum = writeCandidateRows(sheet);
123	                case "collectors" -> rowNum = writeCollectorRows(sheet);
124	                case "departments" -> rowNum = writeDepartmentRows(sheet);
125	                case "courses" -> rowNum = writeCourseRows(sheet);
126	                default -> throw new RuntimeException("Unknown export type: " + type);
127	            }
128	
129	            try (FileOutputStream fos = new FileOutputStream(filePath.toFile())) {
130	                wb.write(fos);
131	            }
132	            return rowNum;
133	        }
134	    }
