145	
146	        try (PrintWriter pw = new PrintWriter(Files.newBufferedWriter(filePath))) {
147	            for (String[] row : rows) {
148	                pw.println(String.join(",", escapeCsvFields(row)));
149	            }
150	        }
151	        return rows.size() - 1; // exclude header
152	    }
