19	                .body(new ApiError(404, "NOT_FOUND", ex.getMessage()));
20	    }
21	
22	    @ExceptionHandler(AccessDeniedException.class)
23	    public ResponseEntity<ApiError> handleForbidden(AccessDeniedException ex) {
24	        return ResponseEntity.status(HttpStatus.FORBIDDEN)
25	                .body(new ApiError(403, "FORBIDDEN", ex.getMessage()));
26	    }
27	
28	    @ExceptionHandler(IllegalArgumentException.class)
29	    public ResponseEntity<ApiError> handleBadRequest(IllegalArgumentException ex) {
30	        return ResponseEntity.badRequest()
31	                .body(new ApiError(400, "BAD_REQUEST", ex.getMessage()));
32	    }
33	
34	    @ExceptionHandler(MethodArgumentNotValidException.class)
35	    public ResponseEntity<ApiError> handleValidation(MethodArgumentNotValidException ex) {
36	        List<String> details = ex.getBindingResult().getFieldErrors().stream()
37	                .map(FieldError::getDefaultMessage).toList();
38	        return ResponseEntity.badRequest()
39	                .body(new ApiError(400, "VALIDATION_ERROR", "Validation failed", details));
40	    }
41	
42	    @ExceptionHandler(RuntimeException.class)
43	    public ResponseEntity<ApiError> handleRuntime(RuntimeException ex) {
44	        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
45	                .body(new ApiError(500, "INTERNAL_ERROR", ex.getMessage()));
