1	package com.eaglepoint.workforce.config;
2	
3	import com.eaglepoint.workforce.service.CustomUserDetailsService;
4	import org.springframework.context.annotation.Bean;
5	import org.springframework.context.annotation.Configuration;
6	import org.springframework.security.authentication.AuthenticationManager;
7	import org.springframework.security.authentication.dao.DaoAuthenticationProvider;
8	import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
9	import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
10	import org.springframework.security.config.annotation.web.builders.HttpSecurity;
11	import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
12	import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
13	import org.springframework.security.crypto.password.PasswordEncoder;
14	import org.springframework.security.web.SecurityFilterChain;
15	import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
16	
17	@Configuration
18	@EnableWebSecurity
19	@EnableMethodSecurity
20	public class SecurityConfig {
21	
22	    private final CustomUserDetailsService userDetailsService;
23	    private final AuditAuthenticationHandler authenticationHandler;
24	    private final RateLimitFilter rateLimitFilter;
25	
26	    public SecurityConfig(CustomUserDetailsService userDetailsService,
27	                          AuditAuthenticationHandler authenticationHandler,
28	                          RateLimitFilter rateLimitFilter) {
29	        this.userDetailsService = userDetailsService;
30	        this.authenticationHandler = authenticationHandler;
31	        this.rateLimitFilter = rateLimitFilter;
32	    }
33	
34	    @Bean
35	    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
36	        http
37	            .addFilterBefore(rateLimitFilter, UsernamePasswordAuthenticationFilter.class)
38	            .csrf(csrf -> csrf.ignoringRequestMatchers("/api/**"))
39	            .authorizeHttpRequests(auth -> auth
40	                .requestMatchers("/login", "/css/**", "/js/**", "/error/**").permitAll()
41	                .requestMatchers("/api/v1/**").authenticated()
42	                .requestMatchers("/admin/**").hasRole("ADMINISTRATOR")
43	                .requestMatchers("/recruiter/**").hasAnyRole("RECRUITER", "ADMINISTRATOR")
44	                .requestMatchers("/dispatch/**").hasAnyRole("DISPATCH_SUPERVISOR", "ADMINISTRATOR")
45	                .requestMatchers("/finance/**").hasAnyRole("FINANCE_CLERK", "ADMINISTRATOR")
46	                .requestMatchers("/search/**", "/exports/**", "/imports/**", "/masterdata/**").authenticated()
47	                .anyRequest().authenticated()
48	            )
49	            .formLogin(form -> form
50	                .loginPage("/login")
51	                .successHandler(authenticationHandler)
52	                .failureHandler(authenticationHandler)
53	                .permitAll()
54	            )
55	            .logout(logout -> logout
56	                .logoutUrl("/logout")
57	                .logoutSuccessUrl("/login?logout")
58	                .permitAll()
59	            )
60	            .sessionManagement(session -> session
61	                .sessionFixation().migrateSession()
62	                .maximumSessions(1)
63	            );
64	
65	        return http.build();
66	    }
67	
68	    @Bean
69	    public DaoAuthenticationProvider authenticationProvider() {
70	        DaoAuthenticationProvider provider = new DaoAuthenticationProvider();
71	        provider.setUserDetailsService(userDetailsService);
72	        provider.setPasswordEncoder(passwordEncoder());
73	        return provider;
74	    }
75	
76	    @Bean
77	    public AuthenticationManager authenticationManager(
78	            AuthenticationConfiguration authConfig) throws Exception {
79	        return authConfig.getAuthenticationManager();
80	    }
81	
82	    @Bean
83	    public PasswordEncoder passwordEncoder() {
84	        return new BCryptPasswordEncoder();
85	    }
86	}
