11	import org.springframework.stereotype.Service;
12	import org.springframework.transaction.annotation.Transactional;
13	
14	import java.util.*;
15	
16	@Service
17	public class SearchSnapshotService {
18	
19	    private final SearchSnapshotRepository snapshotRepository;
20	    private final MatchingService matchingService;
21	    private final ObjectMapper objectMapper;
22	
23	    public SearchSnapshotService(SearchSnapshotRepository snapshotRepository,
24	                                  MatchingService matchingService,
25	                                  ObjectMapper objectMapper) {
26	        this.snapshotRepository = snapshotRepository;
27	        this.matchingService = matchingService;
28	        this.objectMapper = objectMapper;
29	    }
30	
31	    @Transactional
32	    public SearchSnapshot createSnapshot(String name, MatchSearchRequest request,
33	                                          Long createdBy) {
34	        List<MatchResult> results = matchingService.matchCandidates(request);
35	
36	        SearchSnapshot snapshot = new SearchSnapshot();
37	        snapshot.setName(name);
38	        snapshot.setCreatedBy(createdBy);
39	        snapshot.setJobProfileId(request.getJobProfileId());
40	
41	        try {
42	            snapshot.setSearchCriteriaJson(objectMapper.writeValueAsString(request));
43	        } catch (JsonProcessingException e) {
44	            throw new RuntimeException("Failed to serialize search criteria", e);
45	        }
46	
47	        for (MatchResult mr : results) {
48	            CandidateProfile candidate = mr.getCandidate();
49	            String candidateJson = serializeCandidateSnapshot(candidate);
50	
51	            SearchSnapshotResult ssr = new SearchSnapshotResult(
52	                    snapshot,
53	                    candidate.getId(),
54	                    candidate.getFullName(),
55	                    mr.getMatchScore(),
56	                    mr.getFullRationale(),
57	                    candidateJson
58	            );
59	            snapshot.getResults().add(ssr);
60	        }
61	
62	        return snapshotRepository.save(snapshot);
63	    }
64	
65	    @Transactional
66	    public SearchSnapshot createSnapshotFromJobProfile(String name, Long jobProfileId, Long createdBy) {
67	        List<MatchResult> results = matchingService.matchAgainstJobProfile(jobProfileId);
68	
69	        MatchSearchRequest request = new MatchSearchRequest();
70	        request.setJobProfileId(jobProfileId);
71	
72	        SearchSnapshot snapshot = new SearchSnapshot();
73	        snapshot.setName(name);
74	        snapshot.setCreatedBy(createdBy);
75	        snapshot.setJobProfileId(jobProfileId);
76	
77	        try {
78	            snapshot.setSearchCriteriaJson(objectMapper.writeValueAsString(request));
79	        } catch (JsonProcessingException e) {
80	            throw new RuntimeException("Failed to serialize search criteria", e);
81	        }
82	
83	        for (MatchResult mr : results) {
84	            CandidateProfile candidate = mr.getCandidate();
85	            String candidateJson = serializeCandidateSnapshot(candidate);
86	
87	            SearchSnapshotResult ssr = new SearchSnapshotResult(
88	                    snapshot,
89	                    candidate.getId(),
90	                    candidate.getFullName(),
91	                    mr.getMatchScore(),
92	                    mr.getFullRationale(),
93	                    candidateJson
94	            );
95	            snapshot.getResults().add(ssr);
96	        }
97	
98	        return snapshotRepository.save(snapshot);
99	    }
100	
101	    @Transactional(readOnly = true)
102	    public List<SearchSnapshot> findByCreator(Long userId) {
103	        return snapshotRepository.findByCreatedByOrderByCreatedAtDesc(userId);
104	    }
105	
106	    @Transactional(readOnly = true)
107	    public Optional<SearchSnapshot> findByIdWithResults(Long id) {
108	        return snapshotRepository.findByIdWithResults(id);
109	    }
110	
111	    private String serializeCandidateSnapshot(CandidateProfile candidate) {
112	        Map<String, Object> snapshot = new LinkedHashMap<>();
113	        snapshot.put("id", candidate.getId());
114	        snapshot.put("name", candidate.getFullName());
115	        snapshot.put("title", candidate.getCurrentTitle());
116	        snapshot.put("employer", candidate.getCurrentEmployer());
117	        snapshot.put("yearsExperience", candidate.getYearsOfExperience());
118	        snapshot.put("location", candidate.getLocation());
119	        snapshot.put("education", candidate.getEducationLevel());
120	
121	        List<Map<String, Object>> skills = new ArrayList<>();
122	        for (var skill : candidate.getSkills()) {
123	            Map<String, Object> s = new LinkedHashMap<>();
124	            s.put("name", skill.getSkillName());
125	            s.put("years", skill.getYearsExperience());
126	            s.put("proficiency", skill.getProficiency() != null ? skill.getProficiency().name() : null);
127	            skills.add(s);
128	        }
129	        snapshot.put("skills", skills);
130	
131	        try {
132	            return objectMapper.writeValueAsString(snapshot);
133	        } catch (JsonProcessingException e) {
134	            return "{}";
135	        }
136	    }
137	}
